VALUES
  ('elementary-d0d1b9a2-moex-00925', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '依會計法規定，規範公務機關之歲入或經費之預算實施，屬於何種普通公務會計事務？', '["公務財務之會計事務", "公務財物之會計事務", "公務出納之會計事務", "公務歲計之會計事務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:50+00:00", "source_pdf_sha1": "b41f0a91a59d", "answer_pdf_sha1": "29407fcd2776", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00926', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '審計機關審核各機關或各基金決算，應注意事項為何？', '["歲入、歲出是否與預算相符；如不相符，其不符之原因", "歲入、歲出是否平衡；如不平衡，其不平衡之原因", "歲入、歲出是否與國民經濟能力及其發展相適應", "施政計畫、事業計畫或營業計畫已成與未成之程度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:50+00:00", "source_pdf_sha1": "b41f0a91a59d", "answer_pdf_sha1": "29407fcd2776", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00001', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '目前各國衡量一國的經濟成長常會使用國民所得的數據來顯示，但國民所得的數據只是整體與平均經濟 狀況表象，下列何種曲線可以呈現國民所得分配不均程度？', '["恩格爾曲線", "菲利浦曲線", "勞倫斯曲線", "生產可能曲線"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00002', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '某國生產兩種產品（X與Y，分別表示為水平軸與垂直軸），其凹向原點的生產可能曲線上，由左上往右 下依序為A、B、C三個點，下列敘述何者正確？', '["就生產效率的大小而言，A＞B＞C", "多生產一單位X的機會成本為A＞B＞C", "就生產效率的大小而言，A＝B＝C", "多生產一單位Y的機會成本為A＝B＝C"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00003', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '跨太平洋夥伴全面進步協定（CPTPP）旨在促進泛太平洋國家間的貿易自由化。依其宗旨判斷，參與此種 經濟合作組織的國家，會產生下列何種現象？', '["勞動要素可自由流動", "各國間實施關稅保護", "共同發行統一的貨幣", "市場上商品種類增加"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00004', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '對社會而言，下列那一種財貨或服務的機會成本最低？', '["政府提供的免費服務", "不具相對稀少性的物品", "準備拿來當作肥料的雞糞", "無法提升消費者效用的物品"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00005', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '市場上的生產者與消費者會隨著產品價格的上漲或下跌，不斷地調整其生產或消費行為，最後會達到市場 均衡。下列針對此市場均衡的相關敘述，何者正確？', '["無謂損失等於零", "生產者剩餘達到最小值", "社會總剩餘等於消費者剩餘", "社會福利等於社會總效益加社會總成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00006', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '假設政府發出公告：「近來國內經濟發展穩定，經政府核定列冊之低收入戶及中低收入戶，政府會加發生 活補助，低收入戶每人每月發給750元，中低收入戶每人每月發給500元」。前述政策內容，最符合下列 何項理論的內涵？', '["符合多數人福祉的效益主義觀點", "照顧弱勢者權益的社會平等觀點", "追求群體共同利益的社群主義觀點", "透過私利實現公益的自由主義觀點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00007', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '有學者研究指出臺灣高等教育「反向重分配」的事實：社會地位越高的家庭，相對於較低的家庭，其子女反 而能得到較多的政府教育資源。從經濟資本與文化資本兩個概念來觀察，下列敘述何者最能符合題文的描述？', '["父母職業聲望對子女社會地位影響力擴大", "親子間社會地位的世代流動距離得以擴大", "父母的成就動機對子女社會地位流動的影響得以擴大", "父母的教育程度高低對子女社會地位流動的影響變小"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00008', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '有媒體報導，在某國的益智節目中，參賽者被問了一道問題：「在臺灣，人們說食物 QQ 的，是什麼意 思？」答案選項分別是：A.形容媽媽的味道；B.形容食物有嚼勁；C.指食物含有酒精。兩位參賽者討論、 思考後，最終決定選擇C，因而錯失繼續挑戰百萬獎金的機會。而在同一報導中，臺灣網友表示，「這就 內建在腦袋中，就QQ的，要解釋什麼？」對於上述所反映的文化現象，下列敘述何者最為正確？', '["參賽者係身處在該社會環境下的不利處境而無法正確回答", "網友認為「QQ」實無須解釋，係反映我族中心主義的優越態度", "「QQ」作為一種符號，在不同文化下呈現不同的認知與使用意義", "參賽題目設計者認為「QQ」在不同文化下應有著相同的意義"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL)
